inventory.py.content:
def reserve(stock, sku, qty):
    stock[sku] -= qty
    return stock[sku]

tests/test_inventory.py.content:
import pytest
from inventory import reserve

def test_reserve_success():
    stock = {'A': 3}
    assert reserve(stock, 'A', 2) == 1

def test_reserve_insufficient():
    with pytest.raises(ValueError):
        reserve({'A': 1}, 'A', 2)

